import{ConversationCursorPage}from"../../../../core/pagination.js";import{APIResource}from"../../../../core/resource.js";import{path}from"../../../../internal/utils/path.js";import{Roles}from"./roles.js";var Users=class extends APIResource{constructor(){super(...arguments),this.roles=new Roles(this._client)}retrieve(e,t){return this._client.get(path`/organization/users/${e}`,{...t,__security:{adminAPIKeyAuth:!0}})}update(e,t,r){return this._client.post(path`/organization/users/${e}`,{body:t,...r,__security:{adminAPIKeyAuth:!0}})}list(t={},n){return this._client.getAPIList(`/organization/users`,ConversationCursorPage,{query:t,...n,__security:{adminAPIKeyAuth:!0}})}delete(e,t){return this._client.delete(path`/organization/users/${e}`,{...t,__security:{adminAPIKeyAuth:!0}})}};Users.Roles=Roles;export{Users};